import React, { useEffect, useRef, useState } from "react";
import { gsap } from "gsap";

const DashboardPage = ({ user = { name: "Faizan" }, onLogout }) => {
  const [isDark, setIsDark] = useState(true);

  const orbRef = useRef(null);
  const ringsRef = useRef([]);
  const panelsRef = useRef([]);
  const particlesRef = useRef([]);

  useEffect(() => {
    document.body.style.background = "#050508";
    document.body.style.cursor = "none";

    gsap.fromTo(
      panelsRef.current,
      {
        opacity: 0,
        y: 80,
        scale: 0.9,
        filter: "blur(20px)",
      },
      {
        opacity: 1,
        y: 0,
        scale: 1,
        filter: "blur(0px)",
        stagger: 0.08,
        duration: 1.4,
        ease: "power4.out",
      }
    );

    gsap.to(ringsRef.current[0], {
      rotate: 360,
      duration: 18,
      repeat: -1,
      ease: "none",
    });

    gsap.to(ringsRef.current[1], {
      rotate: -360,
      duration: 12,
      repeat: -1,
      ease: "none",
    });

    gsap.to(orbRef.current, {
      y: -20,
      duration: 3,
      repeat: -1,
      yoyo: true,
      ease: "power1.inOut",
    });

    particlesRef.current.forEach((p, i) => {
      gsap.to(p, {
        y: -100,
        opacity: 0,
        duration: 3 + Math.random() * 5,
        repeat: -1,
        delay: i * 0.2,
        ease: "none",
      });
    });

    const moveCursor = (e) => {
      gsap.to(".cursor", {
        x: e.clientX,
        y: e.clientY,
        duration: 0.1,
      });

      gsap.to(".cursor-ring", {
        x: e.clientX,
        y: e.clientY,
        duration: 0.3,
      });
    };

    window.addEventListener("mousemove", moveCursor);

    return () => {
      window.removeEventListener("mousemove", moveCursor);
      document.body.style.cursor = "auto";
    };
  }, []);

  const agents = [
    {
      name: "Neural AI",
      desc: "Advanced cognitive processing system",
      icon: "🧠",
      color: "#A855F7",
    },
    {
      name: "Quantum Analytics",
      desc: "Realtime prediction engine",
      icon: "⚡",
      color: "#00D4FF",
    },
    {
      name: "Autonomous Ops",
      desc: "Self-operating automation workflows",
      icon: "🤖",
      color: "#6EE7B7",
    },
    {
      name: "Vision Matrix",
      desc: "AI vision intelligence",
      icon: "👁️",
      color: "#F472B6",
    },
  ];

  const metrics = [
    {
      title: "Neural Throughput",
      value: "98.2%",
      color: "#A855F7",
    },
    {
      title: "AI Revenue",
      value: "$284K",
      color: "#00D4FF",
    },
    {
      title: "Cognitive Accuracy",
      value: "94.7%",
      color: "#6EE7B7",
    },
    {
      title: "Automation Sync",
      value: "127",
      color: "#F59E0B",
    },
  ];

  return (
    <div
      style={{
        background: "#050508",
        minHeight: "100vh",
        overflow: "hidden",
        position: "relative",
        color: "white",
        fontFamily: "Inter, sans-serif",
      }}
    >
      {/* Cursor */}
      <div
        className="cursor-ring"
        style={{
          width: 40,
          height: 40,
          border: "1px solid rgba(168,85,247,0.6)",
          borderRadius: "50%",
          position: "fixed",
          top: 0,
          left: 0,
          pointerEvents: "none",
          zIndex: 9999,
          transform: "translate(-50%, -50%)",
          backdropFilter: "blur(3px)",
        }}
      />

      <div
        className="cursor"
        style={{
          width: 10,
          height: 10,
          background: "#A855F7",
          borderRadius: "50%",
          position: "fixed",
          top: 0,
          left: 0,
          pointerEvents: "none",
          zIndex: 10000,
          transform: "translate(-50%, -50%)",
          boxShadow: "0 0 20px #A855F7",
        }}
      />

      {/* Animated Grid */}
      <div className="grid-bg" />

      {/* Glow Orbs */}
      <div className="orb orb1" />
      <div className="orb orb2" />

      {/* Floating Particles */}
      {[...Array(25)].map((_, i) => (
        <div
          key={i}
          ref={(el) => (particlesRef.current[i] = el)}
          style={{
            width: 3,
            height: 3,
            borderRadius: "50%",
            background: "#A855F7",
            position: "absolute",
            left: `${Math.random() * 100}%`,
            bottom: "-20px",
            opacity: 0.6,
          }}
        />
      ))}

      {/* Sidebar */}
      <div
        ref={(el) => (panelsRef.current[0] = el)}
        style={{
          position: "fixed",
          left: 20,
          top: 20,
          bottom: 20,
          width: 90,
          background: "rgba(255,255,255,0.04)",
          border: "1px solid rgba(255,255,255,0.08)",
          borderRadius: 30,
          backdropFilter: "blur(30px)",
          display: "flex",
          flexDirection: "column",
          alignItems: "center",
          paddingTop: 30,
          gap: 24,
          zIndex: 20,
        }}
      >
        <div className="logo">⚡</div>

        {["🏠", "🧠", "📊", "🤖", "⚙️"].map((icon, i) => (
          <div
            key={i}
            className="nav-icon"
            style={{
              width: 54,
              height: 54,
              borderRadius: 18,
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
              fontSize: 22,
              background: "rgba(255,255,255,0.03)",
              border: "1px solid rgba(255,255,255,0.06)",
              cursor: "pointer",
            }}
          >
            {icon}
          </div>
        ))}
      </div>

      {/* Main */}
      <div
        style={{
          marginLeft: 130,
          padding: 30,
          position: "relative",
          zIndex: 5,
        }}
      >
        {/* Top Bar */}
        <div
          ref={(el) => (panelsRef.current[1] = el)}
          style={{
            display: "flex",
            justifyContent: "space-between",
            alignItems: "center",
            marginBottom: 40,
          }}
        >
          <div>
            <h1
              style={{
                fontSize: 54,
                fontWeight: 900,
                lineHeight: 1,
                letterSpacing: "-2px",
                marginBottom: 10,
                background:
                  "linear-gradient(135deg,#fff,#A855F7,#00D4FF)",
                WebkitBackgroundClip: "text",
                WebkitTextFillColor: "transparent",
              }}
            >
              Neural Command
            </h1>

            <p
              style={{
                color: "rgba(255,255,255,0.5)",
                fontSize: 16,
              }}
            >
              Welcome back, {user.name}
            </p>
          </div>

          <button
            onClick={onLogout}
            style={{
              background: "rgba(255,255,255,0.05)",
              border: "1px solid rgba(255,255,255,0.08)",
              padding: "14px 24px",
              borderRadius: 18,
              color: "white",
              cursor: "pointer",
              backdropFilter: "blur(20px)",
            }}
          >
            Logout
          </button>
        </div>

        {/* Hero Core */}
        <div
          ref={(el) => (panelsRef.current[2] = el)}
          style={{
            height: 420,
            borderRadius: 40,
            background:
              "linear-gradient(135deg, rgba(168,85,247,0.12), rgba(0,212,255,0.08))",
            border: "1px solid rgba(255,255,255,0.08)",
            backdropFilter: "blur(30px)",
            position: "relative",
            overflow: "hidden",
            marginBottom: 40,
          }}
        >
          {/* AI Core */}
          <div
            ref={orbRef}
            style={{
              position: "absolute",
              left: "50%",
              top: "50%",
              transform: "translate(-50%, -50%)",
              width: 240,
              height: 240,
            }}
          >
            <div
              ref={(el) => (ringsRef.current[0] = el)}
              style={{
                position: "absolute",
                inset: 0,
                borderRadius: "50%",
                border: "2px solid rgba(168,85,247,0.5)",
                boxShadow: "0 0 40px rgba(168,85,247,0.4)",
              }}
            />

            <div
              ref={(el) => (ringsRef.current[1] = el)}
              style={{
                position: "absolute",
                inset: 25,
                borderRadius: "50%",
                border: "2px solid rgba(0,212,255,0.5)",
                boxShadow: "0 0 40px rgba(0,212,255,0.4)",
              }}
            />

            <div
              style={{
                position: "absolute",
                inset: 60,
                borderRadius: "50%",
                background:
                  "radial-gradient(circle,#A855F7,#00D4FF,#050508)",
                boxShadow:
                  "0 0 80px rgba(168,85,247,0.8), 0 0 120px rgba(0,212,255,0.4)",
              }}
            />
          </div>

          {/* Floating Metrics */}
          <div
            style={{
              position: "absolute",
              left: 40,
              top: 40,
            }}
          >
            <div className="mini-card">
              <h4>Realtime Sync</h4>
              <span>99.97%</span>
            </div>
          </div>

          <div
            style={{
              position: "absolute",
              right: 40,
              top: 60,
            }}
          >
            <div className="mini-card">
              <h4>AI Efficiency</h4>
              <span>94.2%</span>
            </div>
          </div>

          <div
            style={{
              position: "absolute",
              bottom: 40,
              left: 60,
            }}
          >
            <div className="mini-card">
              <h4>Operations</h4>
              <span>2,847</span>
            </div>
          </div>

          <div
            style={{
              position: "absolute",
              bottom: 50,
              right: 70,
            }}
          >
            <div className="mini-card">
              <h4>Neural Index</h4>
              <span>87%</span>
            </div>
          </div>
        </div>

        {/* Metrics */}
        <div
          style={{
            display: "grid",
            gridTemplateColumns: "repeat(auto-fit,minmax(260px,1fr))",
            gap: 24,
            marginBottom: 40,
          }}
        >
          {metrics.map((metric, i) => (
            <div
              key={i}
              ref={(el) => (panelsRef.current[3 + i] = el)}
              className="glass-card"
            >
              <div
                style={{
                  width: 60,
                  height: 60,
                  borderRadius: 20,
                  background: `${metric.color}20`,
                  marginBottom: 20,
                  boxShadow: `0 0 30px ${metric.color}55`,
                }}
              />

              <h3
                style={{
                  color: "rgba(255,255,255,0.6)",
                  marginBottom: 10,
                  fontSize: 15,
                }}
              >
                {metric.title}
              </h3>

              <div
                style={{
                  fontSize: 42,
                  fontWeight: 900,
                  color: metric.color,
                }}
              >
                {metric.value}
              </div>
            </div>
          ))}
        </div>

        {/* AI Agents */}
        <div
          ref={(el) => (panelsRef.current[8] = el)}
          style={{
            marginBottom: 50,
          }}
        >
          <h2
            style={{
              fontSize: 38,
              fontWeight: 900,
              marginBottom: 30,
              letterSpacing: "-1px",
            }}
          >
            Autonomous Agents
          </h2>

          <div
            style={{
              display: "grid",
              gridTemplateColumns: "repeat(auto-fit,minmax(280px,1fr))",
              gap: 24,
            }}
          >
            {agents.map((agent, i) => (
              <div
                key={i}
                className="agent-card"
                style={{
                  background:
                    "linear-gradient(135deg, rgba(255,255,255,0.05), rgba(255,255,255,0.02))",
                  border: `1px solid ${agent.color}30`,
                  borderRadius: 30,
                  padding: 30,
                  position: "relative",
                  overflow: "hidden",
                  backdropFilter: "blur(30px)",
                }}
              >
                <div className="agent-glow" />

                <div
                  style={{
                    fontSize: 64,
                    marginBottom: 20,
                  }}
                >
                  {agent.icon}
                </div>

                <h3
                  style={{
                    fontSize: 24,
                    fontWeight: 800,
                    marginBottom: 10,
                  }}
                >
                  {agent.name}
                </h3>

                <p
                  style={{
                    color: "rgba(255,255,255,0.55)",
                    lineHeight: 1.6,
                    marginBottom: 24,
                  }}
                >
                  {agent.desc}
                </p>

                <button
                  style={{
                    background: `${agent.color}20`,
                    border: `1px solid ${agent.color}40`,
                    color: agent.color,
                    padding: "12px 24px",
                    borderRadius: 14,
                    cursor: "pointer",
                    fontWeight: 700,
                  }}
                >
                  Launch Agent
                </button>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* CSS */}
      <style>{`
        *{
          box-sizing:border-box;
        }

        .grid-bg{
          position:absolute;
          inset:0;
          background-image:
          linear-gradient(rgba(255,255,255,0.03) 1px, transparent 1px),
          linear-gradient(90deg, rgba(255,255,255,0.03) 1px, transparent 1px);
          background-size:60px 60px;
          z-index:0;
        }

        .orb{
          position:absolute;
          border-radius:50%;
          filter:blur(100px);
          opacity:0.4;
        }

        .orb1{
          width:500px;
          height:500px;
          background:#A855F7;
          top:-200px;
          left:-150px;
        }

        .orb2{
          width:400px;
          height:400px;
          background:#00D4FF;
          bottom:-150px;
          right:-100px;
        }

        .glass-card{
          background:
          linear-gradient(
          135deg,
          rgba(255,255,255,0.05),
          rgba(255,255,255,0.02)
          );

          border:1px solid rgba(255,255,255,0.08);

          border-radius:30px;
          padding:30px;

          backdrop-filter:blur(30px);

          transition:0.4s ease;

          position:relative;

          overflow:hidden;
        }

        .glass-card:hover{
          transform:
          translateY(-10px)
          scale(1.02);

          box-shadow:
          0 20px 60px rgba(168,85,247,0.25);
        }

        .agent-card{
          transition:0.4s ease;
        }

        .agent-card:hover{
          transform:
          translateY(-12px)
          rotateX(5deg);

          box-shadow:
          0 30px 80px rgba(168,85,247,0.2);
        }

        .agent-glow{
          position:absolute;
          width:200px;
          height:200px;
          border-radius:50%;
          background:rgba(168,85,247,0.2);
          filter:blur(80px);
          top:-50px;
          right:-50px;
        }

        .mini-card{
          background:
          rgba(255,255,255,0.05);

          border:
          1px solid rgba(255,255,255,0.08);

          backdrop-filter:
          blur(20px);

          border-radius:20px;

          padding:18px 24px;

          min-width:160px;
        }

        .mini-card h4{
          margin:0;
          color:rgba(255,255,255,0.5);
          font-size:13px;
          margin-bottom:8px;
        }

        .mini-card span{
          font-size:28px;
          font-weight:800;
        }

        .nav-icon{
          transition:0.3s ease;
        }

        .nav-icon:hover{
          transform:
          scale(1.08);

          background:
          rgba(168,85,247,0.15);

          box-shadow:
          0 0 30px rgba(168,85,247,0.3);
        }

        .logo{
          width:60px;
          height:60px;
          border-radius:20px;

          background:
          linear-gradient(
          135deg,
          #A855F7,
          #00D4FF
          );

          display:flex;
          align-items:center;
          justify-content:center;

          font-size:28px;

          box-shadow:
          0 0 40px rgba(168,85,247,0.5);
        }

        @media(max-width:900px){

          .mini-card{
            display:none;
          }

        }

        @media(max-width:768px){

          .cursor,
          .cursor-ring{
            display:none;
          }

          body{
            cursor:auto !important;
          }

        }

      `}</style>
    </div>
  );
};

export default DashboardPage;
